// Social Media University AI — Daily Training Pools
// Spec: docs/CONTENT-SPEC.md section 5. Plain script, no modules.
window.SMU_DATA = window.SMU_DATA || { schools: [] };

SMU_DATA.training = {
  challenges: [
    { id: "ch-01", title: "The 3-Hook Rewrite", task: "Take your most recent post and write three replacement hooks: one curiosity gap, one status trigger, one loss-framed warning. Read each aloud — if it takes more than 2 seconds to land, cut words until it does.", skill: "viral", minutes: 15, xp: 40 },
    { id: "ch-02", title: "Swipe-Point Autopsy", task: "Rewatch your last 5 videos as a stranger would. Timestamp the exact second you would swipe on each one. Recut your best video to start at that moment — everything before it was throat-clearing.", skill: "viral", minutes: 20, xp: 45 },
    { id: "ch-03", title: "Tier-Up Teardown", task: "Find 3 accounts one size tier above you in your niche. Log their last 9 posts in three columns: format, hook type, CTA. Circle what all three have in common — that overlap is your next test.", skill: "strategy", minutes: 25, xp: 50 },
    { id: "ch-04", title: "Pillar Pressure Test", task: "Write your 3 content pillars, then set a 10-minute timer and list 5 post ideas under each. Any pillar that cannot produce 5 ideas under pressure is too thin — replace it today.", skill: "strategy", minutes: 15, xp: 40 },
    { id: "ch-05", title: "One-Take Teacher", task: "Film a 60-second talking-head teaching exactly one thing, in one take, no script. Watch it back and tally every filler word and dead pause. Reshoot once, starting mid-thought instead of with a greeting.", skill: "video", minutes: 20, xp: 45 },
    { id: "ch-06", title: "The Silent Story", task: "Shoot a 30-second story with zero dialogue using four shots: wide establishing, medium action, close detail, payoff. If a viewer can't follow the story with the sound off, reorder the shots until they can.", skill: "video", minutes: 30, xp: 55 },
    { id: "ch-07", title: "Golden Hour Sprint", task: "In the last hour before sunset, shoot 10 frames of one subject with no repeated composition: shoot through objects, drop low, go backlit, use negative space. Pick the one keeper and note why it won.", skill: "photo", minutes: 20, xp: 45 },
    { id: "ch-08", title: "Cut-on-Action Recut", task: "Open an old edit and move every cut so it lands mid-movement — a hand reaching, a head turning, a door swinging. Cutting on action hides the seam; count how much smoother the same footage feels.", skill: "editing", minutes: 25, xp: 50 },
    { id: "ch-09", title: "The CTA Ladder", task: "Write 5 CTAs for one post at ascending commitment: save it, comment a keyword, share to one person, DM you a word, click the link. Post with the rung that matches where that content sits in your funnel.", skill: "marketing", minutes: 15, xp: 40 },
    { id: "ch-10", title: "Retention Autopsy", task: "Pull the retention graph for your best and worst recent video. At every visible drop-off, write one sentence naming what happens on screen at that second. Patterns beat feelings — keep the notes.", skill: "analytics", minutes: 20, xp: 45 },
    { id: "ch-11", title: "One-Line Positioning", task: "Finish this sentence in under 12 words: 'I help [who] get [outcome] through [mechanism].' Draft it 5 times, keep the sharpest, and check that your last 9 posts actually match it.", skill: "branding", minutes: 15, xp: 40 },
    { id: "ch-12", title: "Open Loop Injection", task: "Take tomorrow's script and open a loop in line one — promise a payoff ('the third one changed everything') and hold the close until the 80% mark. Never close a loop early; that's where retention lives.", skill: "viral", minutes: 20, xp: 45 },
    { id: "ch-13", title: "Format Portfolio Review", task: "List every format you posted in the last 30 days with its reach. Kill the weakest format entirely and schedule the strongest one twice next week. You are a portfolio manager; act like one.", skill: "strategy", minutes: 20, xp: 45 },
    { id: "ch-14", title: "Vertical Coverage Drill", task: "Shoot one simple action — pouring coffee, opening a laptop — with full coverage: wide, medium, close, extreme detail, all framed for 9:16. Then cut them into a 10-second sequence. This is how editors think while shooting.", skill: "video", minutes: 25, xp: 50 },
    { id: "ch-15", title: "First-Frame Fix", task: "Redesign the first frame of your last video: text readable at thumbnail size, subject already in motion, no logo cards, no fade-in. Movement must be visible within half a second of frame one.", skill: "editing", minutes: 15, xp: 40 },
    { id: "ch-16", title: "Nine-Grid Coherence", task: "Plan your next 9 posts as a single grid screenshot: alternate faces, text covers, and detail shots so no two identical tiles touch. Shoot the first one today. Profiles convert visitors; feeds only reach them.", skill: "photo", minutes: 30, xp: 55 },
    { id: "ch-17", title: "Objection Mining", task: "List the 10 objections your ideal customer has before buying — price, time, trust, timing. Write a one-line rebuttal for each, then turn the 3 hardest into next week's content ideas. Objection-led content sells quietly.", skill: "marketing", minutes: 25, xp: 50 },
    { id: "ch-18", title: "Outlier Hunt", task: "Sort your last 90 days by reach and find the post that did at least 2x your median. Write down the single variable most likely responsible — hook, format, topic, or timing — and replicate only that variable this week.", skill: "analytics", minutes: 15, xp: 40 },
    { id: "ch-19", title: "Voice Fingerprint", task: "Write 5 phrases only you would say — your recurring words, metaphors, and sign-offs. Then ban 5 generic phrases you keep using ('game-changer', 'let that sink in'). Pin both lists where you write captions.", skill: "branding", minutes: 20, xp: 45 },
    { id: "ch-20", title: "The Two-Sided Question", task: "End today's post with a genuine either/or question your audience actually debates ('team iPhone or team mirrorless?'). Reply to the first 10 comments within an hour — early replies compound distribution.", skill: "viral", minutes: 10, xp: 30 },
    { id: "ch-21", title: "The 30-Minute Batch", task: "Set a 30-minute timer and script 3 shorts from one pillar using one framework (hook, context, 3 beats, payoff, CTA). Speed forces clarity; you can polish the survivors tomorrow.", skill: "strategy", minutes: 30, xp: 55 },
    { id: "ch-22", title: "B-Roll Bank Run", task: "Film 10 b-roll clips of your actual work — hands, screens, tools, environment — 3 to 5 seconds each, every clip with motivated movement (push in, reveal, rack toward the subject). Save them to a labeled folder; future-you edits faster.", skill: "video", minutes: 25, xp: 50 },
    { id: "ch-23", title: "Sound Design Pass", task: "Reopen an old edit and add a full sound pass: a whoosh on two transitions, a riser before the reveal, one ambient bed, and music ducked -8dB under every spoken line. Export both versions and feel the difference.", skill: "editing", minutes: 25, xp: 50 },
    { id: "ch-24", title: "One Object, Ten Frames", task: "Pick one everyday object and make 10 distinct photos of it with your phone: change height, distance, background, and light direction each frame. Composition is a decision, not a discovery.", skill: "photo", minutes: 20, xp: 45 },
    { id: "ch-25", title: "Story-Sell Rewrite", task: "Rewrite your latest promotional post as a 100-word customer story: their before-state, the turning point, the after-state, then one quiet line about how to get the same result. Delete every adjective that brags.", skill: "marketing", minutes: 20, xp: 45 },
    { id: "ch-26", title: "Follower Quality Check", task: "Compute average reach per post across your last 10 posts, then divide by follower count. Below 20%? Your content is misaligned with who followed you — write one sentence on who your followers actually are versus who you post for.", skill: "analytics", minutes: 15, xp: 40 },
    { id: "ch-27", title: "Bio Rebuild", task: "Rewrite your bio in four lines: who you help, the outcome you deliver, one proof point, one CTA. Read it as a cold visitor with 3 seconds of attention — if line one doesn't name them, start over.", skill: "branding", minutes: 15, xp: 40 },
    { id: "ch-28", title: "The Re-Hook", task: "Add a mid-video re-hook at the 40-50% mark of an existing script — a second promise ('but here's the part nobody tells you'). Long retention tails are built with re-hooks, not with better intros.", skill: "viral", minutes: 15, xp: 40 },
    { id: "ch-29", title: "Platform Fit Audit", task: "Take your 3 best posts and honestly score each 1-5 for fit on Instagram, TikTok, YouTube Shorts, and LinkedIn. Declare one primary platform and one repurposing platform. Focus is a growth strategy.", skill: "strategy", minutes: 20, xp: 45 },
    { id: "ch-30", title: "Walk-and-Talk", task: "Film a talking-head while walking, cutting between 3 locations mid-sentence. Movement injects energy without editing tricks, and the location jumps act as built-in pattern interrupts.", skill: "video", minutes: 20, xp: 45 },
    { id: "ch-31", title: "The 30-Second Cutdown", task: "Take a finished 60-second edit and cut it to 30 without losing the meaning. Kill intros, merge beats, tighten every pause to under 8 frames. Whatever survived is what the video was actually about.", skill: "editing", minutes: 25, xp: 50 },
    { id: "ch-32", title: "Hard Light Challenge", task: "Shoot at midday on purpose. Use the harsh shadows as composition — bars, silhouettes, hard edges across faces and products. Overcast is easy mode; today you learn to shape difficult light.", skill: "photo", minutes: 20, xp: 45 },
    { id: "ch-33", title: "Lead Magnet Sketch", task: "Outline a one-page checklist that solves a 10-minute problem for your audience — specific steps, no theory. Write the comment-keyword CTA you would use to deliver it. Ship the outline; design later.", skill: "marketing", minutes: 25, xp: 50 },
    { id: "ch-34", title: "The One-Variable Test", task: "Design this week's experiment: same script, same edit, two different hooks, posted on comparable days. Write your prediction and the metric that decides it (3-second hold rate). One variable, or you learn nothing.", skill: "analytics", minutes: 15, xp: 40 },
    { id: "ch-35", title: "Signature Frame", task: "Choose one repeatable visual element — a color, a prop, a framing, an opening angle — and build it into today's post. Recognition compounds: viewers should know it's you before they see your name.", skill: "branding", minutes: 20, xp: 45 },
    { id: "ch-36", title: "Trend Translation", task: "Take one trending sound or format and map it onto your niche without losing the mechanic that makes it work. Name the trigger first (surprise, relatability, satisfaction), then rebuild it with your subject matter.", skill: "viral", minutes: 25, xp: 50 },
    { id: "ch-37", title: "Comment Mining Raid", task: "Read 20 comments on a big account in your niche and list 5 desires or frustrations nobody is answering. Turn each into a titled content idea. The audience writes your calendar if you listen.", skill: "strategy", minutes: 25, xp: 50 },
    { id: "ch-38", title: "Lens Compression Study", task: "Shoot the same 10-second scene three ways on your phone: 0.5x wide, 1x, and 2-3x telephoto from further back. Note how the telephoto compresses the background and flatters faces — then decide your default.", skill: "video", minutes: 20, xp: 45 },
    { id: "ch-39", title: "Text Timing Drill", task: "Caption a 30-second clip word-by-word, synced to the voice, with 3 keywords popped in a second color and slight scale-up. Text that arrives with the beat is felt; text that lags is read.", skill: "editing", minutes: 20, xp: 45 },
    { id: "ch-40", title: "Reflection Hunt", task: "Spend 20 minutes shooting only reflections — puddles, windows, screens, sunglasses, car paint. Flip your phone upside down to get the lens closer to the reflective surface. Bring back 5 keepers.", skill: "photo", minutes: 20, xp: 45 },
    { id: "ch-41", title: "DM Flow Draft", task: "Write a 4-message DM sequence that starts when someone comments your keyword: deliver the promised thing first, ask one diagnostic question, add value based on their answer, then — only then — make a soft offer.", skill: "marketing", minutes: 20, xp: 45 },
    { id: "ch-42", title: "Save-Rate Deep Dive", task: "Find your 3 most-saved posts. Saves signal reference value — write one sentence per post naming exactly what viewers plan to come back for. Build next week's post to maximize that same utility.", skill: "analytics", minutes: 15, xp: 40 },
    { id: "ch-43", title: "The Known-For Test", task: "Ask 3 people who follow you — friend, follower, stranger to your niche — what they think you post about. Compare their answers to your intended positioning. The gap between the two is your work.", skill: "branding", minutes: 15, xp: 40 },
    { id: "ch-44", title: "First-Frame Lineup", task: "Screenshot the first frame of your last 6 videos and line them up. Rank them by scroll-stopping power: motion, face, contrast, readable text. Reshoot or re-crop the weakest one today.", skill: "viral", minutes: 20, xp: 45 },
    { id: "ch-45", title: "Flywheel Map", task: "Map how one piece of long-form becomes ten assets: 5 shorts, 3 quote graphics or carousels, 1 email, 1 thread. Draw the actual arrows. Creators burn out making content; systems repurpose it.", skill: "strategy", minutes: 25, xp: 50 },
    { id: "ch-46", title: "Motivated Movement Only", task: "Shoot 5 clips where the camera moves only with a reason: push in on emotion, follow the action, reveal what was hidden, tilt with the eyeline. If you can't say why the camera moves, lock it off.", skill: "video", minutes: 25, xp: 50 },
    { id: "ch-47", title: "Transition Steal", task: "Find a viral transition, step through it frame by frame, and reverse-engineer the mechanics: where the whip lands, what masks the cut, which frames are shared. Then recreate it with your own footage.", skill: "editing", minutes: 30, xp: 55 },
    { id: "ch-48", title: "Blue Hour Brace", task: "Shoot 8 phone photos in the 20 minutes after sunset. Brace your elbows on something solid, use the volume button as shutter, and expose for the highlights. Blue hour makes ordinary streets look cinematic.", skill: "photo", minutes: 20, xp: 45 },
    { id: "ch-49", title: "Offer Stack Build", task: "Write a 5-component stack for your offer: core deliverable, speed element, done-for-you asset, community or access, and a risk reversal. Price each component separately, then present the bundle. Value is built, not claimed.", skill: "marketing", minutes: 30, xp: 55 },
    { id: "ch-50", title: "Drop-Off Timestamping", task: "Across your last 5 videos, mark the 3 steepest retention cliffs and name the on-screen cause of each: pace drop, topic drift, closed loop, static frame. You now have a checklist of your personal failure modes.", skill: "analytics", minutes: 20, xp: 45 },
    { id: "ch-51", title: "Luxury Restraint Pass", task: "Edit your last 3 captions like a luxury brand would: delete hype words, exclamation marks, and emoji clusters; shorten every sentence; let one idea breathe per line. Scarcity of words signals confidence.", skill: "branding", minutes: 20, xp: 45 },
    { id: "ch-52", title: "Curiosity Gap Batch", task: "Write 10 hooks that promise a payoff without revealing it ('the pricing mistake that cost me 40% of my clients'). Then audit each one: if the video can't fully pay it off, the hook is clickbait — cut it.", skill: "viral", minutes: 20, xp: 45 },
    { id: "ch-53", title: "Cadence Contract", task: "Write the weekly posting cadence you can sustain for 90 days at your worst, not your best. Block the creation slots in your actual calendar today. Consistency you keep beats ambition you abandon.", skill: "strategy", minutes: 15, xp: 40 },
    { id: "ch-54", title: "The Payoff Shot", task: "Plan and film an ending worth staying for: a reveal, a transformation, a punchline, a before/after snap. Shoot the ending first, then build the video that earns it. Endings drive rewatches and shares.", skill: "video", minutes: 25, xp: 50 },
    { id: "ch-55", title: "Punch-In Pass", task: "Take a talking-head clip and alternate punch-ins of 10-20% scale on every cut. No new footage required — the zoom pattern alone creates rhythm and hides your jump cuts.", skill: "editing", minutes: 15, xp: 40 },
    { id: "ch-56", title: "Triptych Story", task: "Shoot a 3-photo carousel that tells one story: wide for context, medium for action, detail for emotion. Sequence matters — the detail shot goes last because it rewards the swipe.", skill: "photo", minutes: 20, xp: 45 },
    { id: "ch-57", title: "Proof Inventory", task: "List every proof asset you own: results, testimonials, screenshots, numbers, before/afters. Slot each one into a specific future post. Claims are content; proof is currency.", skill: "marketing", minutes: 20, xp: 45 },
    { id: "ch-58", title: "Weekly Scoreboard", task: "Build a 5-column scoreboard — reach, average retention, saves, follows, replies — and fill in last week's numbers from your analytics. Ten minutes a week of scorekeeping beats an hour of vibes.", skill: "analytics", minutes: 25, xp: 50 },
    { id: "ch-59", title: "Origin Story Draft", task: "Write your 150-word origin story: the stakes, the turning point, the lesson, and one closing line about who you now help. No résumé lines — moments, not milestones. Post it or pin it.", skill: "branding", minutes: 30, xp: 55 },
    { id: "ch-60", title: "Ship the Scary One", task: "Post the idea you have been sitting on for weeks. Give yourself 15 minutes to finish it, not to perfect it. Published and imperfect gathers data; polished and private gathers dust.", skill: "viral", minutes: 15, xp: 40 }
  ],
  editingDrills: [
    { id: "ed-01", title: "The J-Cut Conversation", task: "In CapCut or Premiere Pro, take any two clips and build a J-cut: drag the second clip's audio to start 12-20 frames before its video appears. Do it five times until sliding audio under picture feels automatic.", xp: 30 },
    { id: "ed-02", title: "Cut-on-Action Reps", task: "Load footage of any repeated action and make 10 cuts that each land mid-movement. Then make one cut that lands on stillness and compare — you should now be able to feel a hard cut before you see it.", xp: 30 },
    { id: "ed-03", title: "Speed Ramp Anatomy", task: "In CapCut, apply a custom speed curve to one clip: 100% into 400% into 20% at the moment of impact, back to 100%. Nudge the slow point until it sits exactly on the most interesting frame.", xp: 30 },
    { id: "ed-04", title: "Beat-Grid Edit", task: "Drop a music track on the timeline, mark every downbeat, and cut 8 clips so each edit lands within 2 frames of a marker. Then break the grid once on purpose — the off-beat cut becomes your accent.", xp: 35 },
    { id: "ed-05", title: "Correct, Then Grade", task: "In DaVinci Resolve or CapCut, take two clips shot in different light. First correct both to neutral (white balance, exposure, contrast), then apply one shared look. Toggle before/after — correction is why pro grades match.", xp: 35 },
    { id: "ed-06", title: "Five-SFX Pass", task: "Add exactly five sound effects to a 30-second edit: two transition whooshes, one riser into the reveal, one ambient bed, one UI pop on a text element. Mix each at least -10dB below the voice.", xp: 30 },
    { id: "ed-07", title: "Keyword Pop", task: "Caption a clip, then pick the 3 highest-stakes words and animate each: 8% scale-up, color shift, 2-frame arrival. The viewer's eye should bounce to exactly the words you chose.", xp: 25 },
    { id: "ed-08", title: "The Ruthless Half", task: "Take any finished 60-second edit and deliver a 30-second version. No speed-ups allowed — only cuts. Log what you removed; it is a list of your padding habits.", xp: 35 },
    { id: "ed-09", title: "Match Cut Hunt", task: "Find two clips in your camera roll that share a shape, color, or motion path, and join them with a match cut. Align the matching element to the same screen position on both sides of the cut.", xp: 30 },
    { id: "ed-10", title: "Object-Wipe Transition", task: "Film someone or something passing close to the lens, then use that wipe to hide a cut to a new scene. In CapCut, mask the frames where the foreground fills the screen. One take per side is enough.", xp: 35 },
    { id: "ed-11", title: "Punch-In Rhythm", task: "On a single talking-head take, create a jump-cut rhythm: remove every breath and stumble, then alternate 100% and 115% scale on consecutive cuts. Watch it once muted — the rhythm should read visually.", xp: 25 },
    { id: "ed-12", title: "Silence Surgery", task: "Run a 60-second talking clip and cut every pause longer than 10 frames. Then restore exactly one pause before the most important line. Silence you choose is emphasis; silence you keep by accident is drag.", xp: 25 },
    { id: "ed-13", title: "Stills That Move", task: "Build a 15-second montage from 8 photos using scale and position keyframes — each still gets a subtle push or drift (2-5% over its duration), alternating direction. Cut it to a beat and it reads as footage.", xp: 30 },
    { id: "ed-14", title: "The Reveal Ramp", task: "Edit a product or car reveal: slow build at 80% speed, ramp to 300% on the approach, hard slow to 15% the frame the subject fills the screen, bass hit on the slow point. Export vertical.", xp: 35 },
    { id: "ed-15", title: "Ducking Discipline", task: "Set up audio ducking so music drops 8-12dB whenever the voice enters, with a 10-frame recovery. In Resolve use the Fairlight compressor sidechain; in CapCut, keyframe it manually on three voice entrances.", xp: 30 },
    { id: "ed-16", title: "Frame-by-Frame Steal", task: "Screen-record a transition you admire, step through it frame by frame, and write the recipe: how many frames each phase lasts, what hides the cut, where the motion blur lives. Rebuild it with your footage.", xp: 40 },
    { id: "ed-17", title: "Two Cold Opens", task: "Export the same edit twice with different first 3 seconds: version A opens on the payoff teased, version B opens on the process. Post or share both privately and note which holds attention longer.", xp: 30 },
    { id: "ed-18", title: "Slow-Motion Integrity", task: "Take a 60fps clip, conform it to 24fps for true 2.5x slow motion, and compare against the same clip slowed digitally with optical flow. Learn which artifacts appear and when each method is safe.", xp: 30 },
    { id: "ed-19", title: "The Quiet Luxury Grade", task: "Grade one clip for the luxury look: warm highlights, gently lifted blacks, desaturated midtone greens, contrast eased off 10%. No teal-orange push. The goal is a frame that feels expensive before anything happens.", xp: 35 },
    { id: "ed-20", title: "Hook-Line Zoom", task: "Keyframe a slow 8% push-in that spans your opening line, ending exactly as the sentence lands. One move, one sentence. This micro-zoom is the cheapest retention device in editing — learn its length by feel.", xp: 25 }
  ],
  photoDrills: [
    { id: "ph-01", title: "Ten Angles, One Object", task: "Choose one object and shoot 10 genuinely different compositions: eye level, top-down, ground level, through something, reflected, backlit, negative space, tight detail, environmental, and one rule-breaker.", xp: 30 },
    { id: "ph-02", title: "Window Light Portrait", task: "Place a subject at 45 degrees to a window, phone between them and the glass. Shoot at three distances from the window and watch the shadow side deepen. Tap the face to expose, then drag exposure down slightly.", xp: 30 },
    { id: "ph-03", title: "Negative Space Set", task: "Shoot 5 photos where the subject occupies less than a third of the frame and empty space does the talking — sky, wall, water, shadow. Place the subject on a thirds intersection, never dead center.", xp: 25 },
    { id: "ph-04", title: "Leading Lines Walk", task: "Take a 15-minute walk and shoot 8 frames where a line — railing, curb, shadow, lane marking — pulls the eye to your subject. If a line leads out of frame instead of into it, recompose.", xp: 25 },
    { id: "ph-05", title: "Backlit Discipline", task: "Shoot a backlit subject at golden hour three ways: exposed for the subject (blown sky), exposed for the sky (silhouette), and balanced with AE lock plus a small exposure lift. Keep all three and label them.", xp: 30 },
    { id: "ph-06", title: "The Hero Angle", task: "Shoot a product, car, or sneaker from ankle height, phone tilted slightly up, subject filling the lower two-thirds. Low angle plus tight crop is the fastest way to make anything look dominant.", xp: 25 },
    { id: "ph-07", title: "Reflection Session", task: "Find three reflective surfaces — puddle, window, phone screen — and shoot the subject through each. Turn the phone upside down so the lens sits millimeters from the surface; the reflection doubles in size.", xp: 30 },
    { id: "ph-08", title: "Frame Within a Frame", task: "Shoot 6 photos where something in the scene frames your subject: a doorway, mirror, arch, car window, gap between objects. The inner frame should be darker or softer than the subject it holds.", xp: 25 },
    { id: "ph-09", title: "Exposure Triangle Sim", task: "In your phone's pro mode, shoot one scene at three ISO values and three shutter speeds, keeping the scene identical. Zoom into the shadows of each frame and find exactly where noise becomes visible on your device.", xp: 35 },
    { id: "ph-10", title: "Flat Lay Geometry", task: "Build a top-down flat lay with exactly three props on a clean surface. Shoot near a window, rotate the layout 45 degrees at a time, and reshoot until the shadows fall in one consistent direction.", xp: 30 },
    { id: "ph-11", title: "Texture Macro Five", task: "Shoot 5 extreme close-ups of texture — fabric weave, leather grain, condensation, brushed metal, skin of fruit. Get as close as your lens allows before it hunts focus, then back off one centimeter.", xp: 25 },
    { id: "ph-12", title: "One-Color Story", task: "Shoot 8 photos in 30 minutes where a single accent color appears in every frame. Constraint sharpens seeing: you will start noticing composition everywhere the color hides.", xp: 30 },
    { id: "ph-13", title: "Portrait Mode Audit", task: "Shoot the same portrait with portrait mode on and off. Zoom into hair edges, glasses, and ears to find where computational blur breaks. Learn the failure cases so you know when to trust it.", xp: 25 },
    { id: "ph-14", title: "Panning for Motion", task: "Track a moving subject — cyclist, car, dog — swinging your whole torso, and shoot in burst mid-pan. You want a sharp subject against a streaked background. Expect 20 failures per keeper; that is the ratio.", xp: 35 },
    { id: "ph-15", title: "Three-Tile Sequence", task: "Shoot 3 photos designed to sit side by side in a feed row: matching tones, one visual thread running through all three, horizon lines aligned. Composite them in any grid-preview app before committing.", xp: 30 },
    { id: "ph-16", title: "Noon Shadow Play", task: "Shoot in the hardest light of the day and make the shadow the subject: fence patterns on a wall, a silhouette on pavement, half a face in darkness. Expose for the highlights and let the blacks crush.", xp: 30 },
    { id: "ph-17", title: "One Photo, Three Edits", task: "Take one photo and produce three distinct edits in your phone editor: clean and true-to-life, dark and moody, bright and airy. Save all three and note which one matches the feed you are building.", xp: 30 },
    { id: "ph-18", title: "Symmetry Hunt", task: "Find and shoot 6 symmetrical compositions — architecture, reflections, centered hallways. Use the grid overlay and align the axis perfectly; symmetry forgives nothing at 98%.", xp: 25 },
    { id: "ph-19", title: "Wide-Medium-Detail", task: "Tell one story in three frames: a wide that sets the scene, a medium that shows the action, a detail that carries the emotion. Shoot all three within 10 minutes of each other so the light matches.", xp: 30 },
    { id: "ph-20", title: "Blue Hour Handheld", task: "In the 20 minutes after sunset, shoot 8 frames bracing your elbows on a wall or knee, using the volume button as the shutter and a 3-second timer for the sharpest frame. Expose for the sky and let windows glow.", xp: 30 }
  ],
  marketingDrills: [
    { id: "mk-01", title: "PAS Rewrite", task: "Rewrite your pinned post using Problem-Agitate-Solve: name the pain in line one, make it vivid for two lines, then present the fix. Compare word counts — PAS usually says more with less.", xp: 30 },
    { id: "mk-02", title: "The So-That Chain", task: "List 5 features of your offer, then chain each one: 'which means... so that... so you feel...'. Stop only when you hit an emotion. Publish benefits from the end of the chain, never the start.", xp: 30 },
    { id: "mk-03", title: "Keyword CTA Batch", task: "Write 10 comment-keyword CTAs ('Comment SYSTEM and I'll send the template'). Each must promise a specific deliverable, use a one-word trigger, and be honest about what arrives in the DM.", xp: 25 },
    { id: "mk-04", title: "Objection Map", task: "Write the 10 objections that stop your ideal buyer — price, time, skepticism, timing, spouse, past failures. Draft a one-line rebuttal for each that uses proof or reframing, never pressure.", xp: 35 },
    { id: "mk-05", title: "Three Openers, Three Triggers", task: "Write the same message three ways: one opening with curiosity, one with proof, one with status. Send each aloud past your own skepticism — the one you cannot roll your eyes at wins.", xp: 25 },
    { id: "mk-06", title: "Testimonial Mining", task: "Take one real client result and extract 3 content angles from it: the before-state story, the specific mechanism that worked, and the objection it disproves. One result, three posts.", xp: 30 },
    { id: "mk-07", title: "Funnel on a Napkin", task: "Sketch your funnel in three rows — TOFU, MOFU, BOFU — and write one content idea per row: broad and emotional at the top, comparison and proof in the middle, offer and urgency at the bottom.", xp: 35 },
    { id: "mk-08", title: "Anchor Before Price", task: "Write the 4 sentences that come before your price reveal: the cost of the problem, the price of alternatives, the value of each component, then your number. Read it with and without the anchor sentences.", xp: 30 },
    { id: "mk-09", title: "The No-Pitch DM Script", task: "Draft a 4-message DM flow: deliver the promised resource instantly, ask one diagnostic question, respond with tailored value, then offer the next step only if their answer qualifies them.", xp: 30 },
    { id: "mk-10", title: "100-Word Story Sell", task: "Rewrite any promotional message as a 100-word customer story with a before, a turn, and an after. End with one quiet line: 'If that sounds familiar, the link is in my bio.' Delete every superlative.", xp: 30 },
    { id: "mk-11", title: "Ad Hook Ten", task: "Write 10 first lines for a paid ad without using 'secret', 'hack', 'insane', or 'game-changer'. Lead with a number, a contrarian claim, a named mistake, or a specific result instead.", xp: 30 },
    { id: "mk-12", title: "Only-We Statement", task: "Draft your USP three times in the form 'The only [category] that [distinct mechanism] for [specific person].' Test each draft: if a competitor could honestly say it, it is not a USP yet.", xp: 30 },
    { id: "mk-13", title: "Honest Urgency", task: "Write genuine urgency for your offer using only true constraints — a real cohort date, real capacity, a real price change and its reason. Fake countdowns train audiences to ignore you; real deadlines train them to act.", xp: 25 },
    { id: "mk-14", title: "Lead Magnet Blueprint", task: "Outline a checklist-style lead magnet that solves one painful 10-minute problem completely. Title it with the outcome and a number ('The 9-Point Pre-Post Checklist'), then list every step it contains.", xp: 35 },
    { id: "mk-15", title: "Competitor Gap Read", task: "Read 20 comments on a competitor's popular post and list 5 desires or complaints they never address. Write one sentence per gap on how your offer or content fills it.", xp: 30 },
    { id: "mk-16", title: "Guarantee Drafts", task: "Write 3 risk-reversal guarantees for your offer, ranked from safe to bold — refund, redo-until-result, pay-only-on-outcome. For each, note what would have to be true operationally for you to honor it.", xp: 30 },
    { id: "mk-17", title: "Soft Ask vs Direct Ask", task: "Write two CTAs for tomorrow's post: a soft ask ('save this for your next shoot') and a direct ask ('DM me AUDIT and I'll review your profile'). Predict the winner in writing, then check reality.", xp: 25 },
    { id: "mk-18", title: "Value Ladder Map", task: "Map your value ladder on one page: free content, low-ticket entry, core offer, premium tier — with a price and a promise for each rung, and one sentence on how each rung sells the next.", xp: 35 },
    { id: "mk-19", title: "Reason-Why Discount", task: "Write a discount announcement with a true reason attached — end of quarter, new version launching, first 10 students shaping the curriculum. A justified discount preserves the price integrity a bare one destroys.", xp: 25 },
    { id: "mk-20", title: "Proof Ledger", task: "Build your proof ledger: every number, screenshot, testimonial, and before/after you legitimately own. Mark each as cold-audience proof (results) or warm-audience proof (process), and schedule where each will appear.", xp: 30 }
  ],
  quizBank: [
    { q: "Modern short-video algorithms primarily distribute content based on what?", options: ["Your follower count", "How many hashtags you use", "Your posting time", "Predicted engagement from interest-graph signals"], answer: 3, why: "Platforms like TikTok rank against the interest graph — predicted watch and engagement per viewer — not your social graph or follower size.", skill: "strategy" },
    { q: "What typically happens to a new post before it reaches wide distribution?", options: ["It is shown to a small test audience whose response decides further reach", "It is manually reviewed by moderators", "It goes to all followers simultaneously", "It waits 24 hours for indexing"], answer: 0, why: "Platforms seed content to a test batch and expand distribution only if retention and engagement clear the bar.", skill: "strategy" },
    { q: "How many content pillars should most creators run?", options: ["One, to stay hyper-focused", "Ten or more, for variety", "Three to five, deep enough to own and broad enough to sustain", "Pillars are outdated"], answer: 2, why: "3-5 pillars give the algorithm a clear signal of what you are about while leaving room to produce endlessly.", skill: "strategy" },
    { q: "You can post daily at 7/10 quality or twice weekly at 9/10. Early on, which usually grows faster?", options: ["Twice weekly, because only excellence spreads", "Neither, cadence is irrelevant", "Daily, because volume buys data and reps that compound into quality", "Alternate weeks between the two"], answer: 2, why: "Early growth is a learning problem: more shots on goal means faster feedback loops, and quality rises with reps.", skill: "strategy" },
    { q: "A post massively outperforms your median reach. What is the strategic move?", options: ["Celebrate and move on", "Delete and repost it for more reach", "Isolate the variable that drove it and replicate that variable deliberately", "Immediately run ads behind it"], answer: 2, why: "Outliers are experiments that worked — the growth comes from identifying and repeating the responsible variable.", skill: "strategy" },
    { q: "What does the 70/20/10 content mix refer to?", options: ["70% proven formats, 20% iterations, 10% wild experiments", "70% selling, 20% teaching, 10% entertainment", "70% shorts, 20% stories, 10% long-form", "70% trending sounds, 30% original audio"], answer: 0, why: "A portfolio approach: mostly bankers, some variations, and a slice of high-risk bets that can become new bankers.", skill: "strategy" },
    { q: "Why does niching down usually accelerate early growth?", options: ["The algorithm can classify you faster and show you to the right viewers", "Smaller audiences are easier to impress", "It reduces how much content you need", "Broad topics are penalized by moderation"], answer: 0, why: "A tight topic cluster helps the platform match you to a well-defined interest group, which lifts average watch time and follows.", skill: "strategy" },
    { q: "Which follower behavior tells the algorithm your content deserves non-follower reach?", options: ["Following you back", "Profile visits after viewing", "Strong completion and engagement from the followers shown first", "Turning on notifications"], answer: 2, why: "Follower response is the first test cell; strong retention there earns expansion to cold audiences.", skill: "strategy" },
    { q: "What is an open loop?", options: ["A video with no ending", "A looping video that replays seamlessly", "A CTA asking viewers to comment", "An unanswered question planted early that viewers stay to resolve"], answer: 3, why: "Open loops exploit the brain's need for closure — tension planted in the hook holds attention until it resolves.", skill: "viral" },
    { q: "The real job of the first 3 seconds is to...", options: ["Summarize the whole video", "Introduce yourself and your brand", "Earn the next 3 seconds", "Display your logo for recognition"], answer: 2, why: "Retention is won moment to moment; the opening exists only to buy the following beat, not to explain everything.", skill: "viral" },
    { q: "What is a pattern interrupt?", options: ["A scheduled break from posting", "Blocking trolls in comments", "Changing your niche mid-channel", "An unexpected visual or audio shift that resets fading attention"], answer: 3, why: "Sudden changes — angle, sound, location, prop — spike attention exactly when the brain starts to predict and disengage.", skill: "viral" },
    { q: "A curiosity-gap hook becomes clickbait when...", options: ["It creates tension the video never actually pays off", "It uses a number", "It runs longer than 5 seconds", "It appears in the caption too"], answer: 0, why: "The gap is legitimate only if the payoff genuinely closes it; unpaid promises destroy trust and rewatch behavior.", skill: "viral" },
    { q: "Which engagement signal generally correlates most with explosive reach?", options: ["Shares, because each one recruits a new viewer directly", "Likes", "Comments from your existing fans", "Profile visits"], answer: 0, why: "A share is both a strong quality signal and a literal distribution event — the viewer does the algorithm's job for it.", skill: "viral" },
    { q: "Which content type is engineered for saves?", options: ["Reaction content", "Reference content viewers will need again, like checklists and settings", "Vlogs", "Duets and stitches"], answer: 1, why: "People save what they plan to return to — utility with future value is the save trigger.", skill: "viral" },
    { q: "A hook that says 'You're editing your Reels wrong' primarily triggers...", options: ["Curiosity about your biography", "Loss aversion — fear of an ongoing invisible mistake", "Status envy", "Humor"], answer: 1, why: "Framing an existing behavior as a costly mistake activates loss aversion, a stronger motivator than promised gains.", skill: "viral" },
    { q: "Where should a mid-video re-hook typically land?", options: ["In the first second", "In the final frame", "Around the 40-60% mark, where mid-video drop-off accelerates", "Only in videos over 3 minutes"], answer: 2, why: "A second promise planted mid-video re-tensions the viewers whose original curiosity is nearly spent.", skill: "viral" },
    { q: "What does AVD stand for?", options: ["Average View Duration", "Automatic Video Distribution", "Audience Value Density", "Average Viewer Demographics"], answer: 0, why: "AVD — average view duration — is the core watch-time metric platforms use to judge how long you actually hold people.", skill: "video" },
    { q: "The primary purpose of b-roll over a talking-head is to...", options: ["Fill time between points", "Show what is being said so the viewer processes it visually while listening", "Hide bad lighting", "Make videos longer for watch time"], answer: 1, why: "B-roll converts audio claims into visual evidence and doubles as a retention device by refreshing the frame.", skill: "video" },
    { q: "When framing for 9:16 vertical, you should...", options: ["Keep key action in the middle band, clear of UI zones at top and bottom", "Center everything and ignore edges", "Shoot 16:9 and crop later", "Always shoot from below"], answer: 0, why: "Platform UI — captions, buttons, usernames — eats the top and bottom of vertical frames, so critical content lives in the safe middle band.", skill: "video" },
    { q: "Basic coverage of a scene means shooting...", options: ["The same action at wide, medium, and close so the editor can build rhythm", "One long continuous take", "Only close-ups to feel intimate", "Ten takes of the same framing"], answer: 0, why: "Multiple shot sizes of one action give the edit options for pacing, emphasis, and invisible cuts.", skill: "video" },
    { q: "Starting a talking-head video mid-thought works because...", options: ["It saves scripting time", "It skips the greeting viewers use as their cue to swipe", "It hides your nervousness", "Platforms trim intros automatically"], answer: 1, why: "'Hey guys, welcome back' signals a slow start; cold-opening inside the idea removes the swipe cue entirely.", skill: "video" },
    { q: "Camera movement is 'motivated' when...", options: ["It uses a gimbal", "It follows a trend", "It exists for a narrative reason — revealing, following, or intensifying", "It happens on every shot"], answer: 2, why: "Movement should answer 'why is the camera moving?' — reveals, follows, and pushes with purpose read as intentional cinema.", skill: "video" },
    { q: "Shooting a face with a longer (telephoto) focal length from further back tends to...", options: ["Distort the nose outward", "Reduce sharpness dramatically", "Compress features and backgrounds, flattering the subject", "Make lighting irrelevant"], answer: 2, why: "Telephoto compression flattens facial features and pulls the background closer, which is why it flatters portraits.", skill: "video" },
    { q: "In the exposure triangle, raising which setting adds noise/grain?", options: ["Shutter speed", "Aperture", "ISO", "White balance"], answer: 2, why: "ISO amplifies the sensor signal — more amplification, more visible noise, especially in shadows.", skill: "photo" },
    { q: "A lower f-number like f/1.8 gives you...", options: ["A deeper depth of field", "A darker image", "More motion blur", "A shallower depth of field with more background blur"], answer: 3, why: "Wider apertures (smaller f-numbers) narrow the plane of focus, separating subject from background.", skill: "photo" },
    { q: "Golden hour light is prized because it is...", options: ["Soft, warm, and directional, wrapping subjects with long gentle shadows", "Brighter than midday", "Blue and moody", "Perfectly even in all directions"], answer: 0, why: "The low sun travels through more atmosphere, diffusing and warming the light while giving it flattering direction.", skill: "photo" },
    { q: "An overcast sky effectively acts as...", options: ["A giant softbox producing shadowless, even light", "A polarizing filter", "A warming filter", "A reason not to shoot"], answer: 0, why: "Clouds diffuse the sun into a huge soft source — ideal for portraits and detail work with no harsh shadows.", skill: "photo" },
    { q: "Negative space in composition is used to...", options: ["Hide mistakes in the background", "Give the subject isolation and visual weight through emptiness", "Fill the frame edge to edge", "Increase file compression"], answer: 1, why: "Deliberate emptiness directs the eye and lends a premium, editorial feel — which is why luxury brands lean on it.", skill: "photo" },
    { q: "Leading lines work because they...", options: ["Make photos look wider", "Add symmetry automatically", "Exploit how the eye follows linear paths toward the subject", "Replace the need for focus"], answer: 2, why: "The eye instinctively travels along lines; aim them at your subject and you control the viewer's gaze.", skill: "photo" },
    { q: "For sharp handheld phone photos in low light, you should...", options: ["Zoom in digitally first", "Brace your body, use burst or a timer, and let the phone stack exposures", "Raise exposure compensation to maximum", "Always use the flash"], answer: 1, why: "Stability plus computational stacking (night mode) beats brute-force brightness, which just adds blur and noise.", skill: "photo" },
    { q: "In a J-cut, what happens?", options: ["Video changes before its audio arrives", "Two clips play side by side", "The audio is muted across the cut", "The next clip's audio starts before its video appears"], answer: 3, why: "Hearing the next scene before seeing it pulls viewers across the edit — the classic tool for smooth, conversational flow.", skill: "editing" },
    { q: "Why do editors cut on action?", options: ["Movement across the cut masks the edit so it feels continuous", "It saves timeline space", "It syncs better with music", "It reduces export time"], answer: 0, why: "The viewer's eye tracks the motion, not the splice — cuts hidden inside movement read as one continuous moment.", skill: "editing" },
    { q: "The correct professional order for color work is...", options: ["Grade first for style, then correct", "Correct each clip to neutral, then apply the creative grade", "Apply a LUT and stop", "Only adjust saturation"], answer: 1, why: "Correction normalizes exposure and white balance so one creative grade sits consistently across every shot.", skill: "editing" },
    { q: "A speed ramp is...", options: ["A gradual or sudden change of clip speed within the same shot", "Rendering at a higher frame rate", "Cutting faster as the video progresses", "An audio fade technique"], answer: 0, why: "Ramping between fast and slow inside one clip creates impact moments — the signature of reveal and action edits.", skill: "editing" },
    { q: "For short-form pacing, a common target is...", options: ["A visual change roughly every 1.5-3 seconds", "One cut per 10 seconds", "No cuts at all", "Cuts only at sentence ends"], answer: 0, why: "Frequent visual refresh — cut, punch-in, b-roll, or graphic — keeps the frame novel before attention decays.", skill: "editing" },
    { q: "Audio ducking means...", options: ["Removing all background music", "Pitching audio down", "Recording in a quiet room", "Automatically lowering music when the voice speaks"], answer: 3, why: "Ducking keeps the voice intelligible while preserving musical energy — typically an 8-12dB dip under dialogue.", skill: "editing" },
    { q: "A match cut joins two shots by...", options: ["Matching their duration", "Using the same audio", "Matching a shape, motion, or composition across the cut", "Crossfading slowly"], answer: 2, why: "Visual continuity of form or movement makes the cut feel inevitable and often delivers a satisfying reveal.", skill: "editing" },
    { q: "True slow motion comes from...", options: ["Stretching any clip on the timeline", "Shooting at a high frame rate and conforming to a lower one", "Adding motion blur in post", "Lowering the shutter speed"], answer: 1, why: "60 or 120fps footage conformed to 24/30fps plays every captured frame slowly and smoothly; digital stretching invents frames.", skill: "editing" },
    { q: "The Problem-Agitate-Solve framework works because...", options: ["It is shorter than other frameworks", "Pain acknowledged and intensified makes the solution feel necessary, not optional", "It avoids mentioning the product", "It relies on humor"], answer: 1, why: "Buyers move on urgency — agitation converts a known problem into a felt one before the solution appears.", skill: "marketing" },
    { q: "'1TB of storage' is a feature. The benefit is...", options: ["A terabyte is 1024 gigabytes", "Industry-leading capacity", "Never deleting a memory to make room for a new one", "It comes in silver"], answer: 2, why: "Benefits translate specs into felt outcomes — what the feature lets the customer do or stop worrying about.", skill: "marketing" },
    { q: "Comment-keyword CTAs ('Comment GROW for the guide') are powerful because they...", options: ["Trick the algorithm", "Combine engagement signal, lead capture, and a DM conversation in one action", "Replace the need for good content", "Are impossible to ignore"], answer: 1, why: "One comment boosts distribution, opts the viewer into a DM flow, and starts a 1:1 conversation — three wins from one tap.", skill: "marketing" },
    { q: "The job of top-of-funnel (TOFU) content is to...", options: ["Close sales directly", "Retarget past buyers", "Explain pricing", "Reach and resonate with strangers who don't yet know they need you"], answer: 3, why: "TOFU earns attention and relevance with broad, emotional, or entertaining angles; selling comes downstream.", skill: "marketing" },
    { q: "Risk reversal in an offer means...", options: ["Raising the price to signal quality", "Hiding the terms and conditions", "Only selling to warm audiences", "Shifting the risk of the purchase from buyer to seller, e.g. a strong guarantee"], answer: 3, why: "When the seller absorbs downside risk, the buyer's biggest silent objection — 'what if it doesn't work?' — dissolves.", skill: "marketing" },
    { q: "Which testimonial is most persuasive?", options: ["'Amazing service, highly recommend!'", "'Life-changing!!!' with five stars", "'Booked 9 discovery calls in 3 weeks after rewriting my profile with this system'", "A celebrity emoji comment"], answer: 2, why: "Specific numbers and timelines read as evidence; vague praise reads as decoration.", skill: "marketing" },
    { q: "Urgency in an offer should always be...", options: ["Manufactured with countdown timers", "Repeated in every post", "Real — a true deadline, capacity limit, or price change with a reason", "Avoided entirely"], answer: 2, why: "False scarcity trains audiences to ignore your deadlines; honest constraints train them to act on time.", skill: "marketing" },
    { q: "The strongest personal-brand positioning is being known...", options: ["For many things to maximize reach", "For one specific thing by a specific audience", "As a mystery with no clear topic", "For posting most frequently"], answer: 1, why: "Memory is single-slot: people file you under one label, so the brand's job is choosing that label deliberately.", skill: "branding" },
    { q: "A visual identity system succeeds when...", options: ["Every post looks identical", "It uses trending colors", "It changes weekly to stay fresh", "Followers recognize your content in the feed before seeing your name"], answer: 3, why: "Consistent color, type, framing, and rhythm build pre-attentive recognition — the feed-scroll equivalent of a logo.", skill: "branding" },
    { q: "Classic luxury brand codes include...", options: ["Restraint, negative space, scarcity, and unhurried pacing", "Loud claims, discounts, and urgency", "Maximum posting frequency", "Bright saturated color palettes"], answer: 0, why: "Luxury signals through what it withholds — sparse copy, quiet visuals, and scarcity imply value without arguing for it.", skill: "branding" },
    { q: "Creators fear niching down because it shrinks the audience. In practice, it usually...", options: ["Kills growth permanently", "Deepens resonance and accelerates growth by making you the obvious choice for someone specific", "Only works for big accounts", "Requires changing platforms"], answer: 1, why: "A smaller, sharper promise wins the follow decision more often — relevance beats reach at the moment of choice.", skill: "branding" },
    { q: "Brand voice is best defined as...", options: ["The audio quality of your videos", "The consistent personality in your words — vocabulary, rhythm, and stance", "Your logo and colors", "The topics you cover"], answer: 1, why: "Voice is how you sound in text and speech; held consistent, it becomes recognizable even without visuals.", skill: "branding" },
    { q: "Audience trust is built primarily through...", options: ["Viral moments", "Consistent delivery on promises over time, backed by visible proof", "Follower count milestones", "Expensive production value"], answer: 1, why: "Trust is accumulated evidence: showing up as promised, being right repeatedly, and receipts over rhetoric.", skill: "branding" },
    { q: "A personal brand outperforms a faceless page at monetization mostly because...", options: ["Faces get better reach", "Logos are expensive", "Platforms verify humans faster", "People buy from people — face and story create parasocial trust that converts"], answer: 3, why: "Familiarity with a real person compounds into trust, and trust is the conversion variable money follows.", skill: "branding" },
    { q: "For short-form video, which metric best predicts further distribution?", options: ["Like count", "Number of hashtags", "Caption length", "Completion/retention rate"], answer: 3, why: "Platforms optimize for time well spent — videos that hold viewers to the end earn the next test audience.", skill: "analytics" },
    { q: "Comparing watch percentage across videos of different lengths is misleading because...", options: ["Short videos inflate percentages — a 7-second video at 90% holds less attention than a 60-second video at 50%", "Percentages are rounded", "Platforms hide true numbers", "Longer videos always win"], answer: 0, why: "Judge retention in context of duration: absolute seconds watched and shape of the curve tell the real story.", skill: "analytics" },
    { q: "A valid content experiment changes...", options: ["Everything at once for maximum learning", "Only the posting time", "One variable at a time so results are attributable", "Nothing — just repost"], answer: 2, why: "If hook, topic, and format all change together, you cannot know what caused the difference.", skill: "analytics" },
    { q: "High reach but almost no new follows usually means...", options: ["The algorithm is broken", "The content entertains broadly but gives no reason to expect valuable future content from you", "You posted at the wrong time", "Your bio link is broken"], answer: 1, why: "Follows are a bet on your future output — reach without follows signals missing identity or positioning in the content.", skill: "analytics" },
    { q: "A spike in saves tells you the post has...", options: ["Gone viral already", "Too much text", "Reached the wrong audience", "Reference value viewers plan to return to"], answer: 3, why: "Saving is deferred consumption — the clearest signal that content is useful beyond the moment.", skill: "analytics" },
    { q: "Before declaring a format 'dead' for your account, you should have...", options: ["One data point", "At least 3-5 attempts, since single posts vary wildly by luck and seed audience", "A competitor's opinion", "A week of no posting"], answer: 1, why: "Distribution has high variance; small samples produce false verdicts in both directions.", skill: "analytics" },
    { q: "On YouTube, 'session time' rewards creators whose videos...", options: ["Are longest in runtime", "Keep viewers watching on the platform afterward, via suggested and series viewing", "Upload most frequently", "Use the most tags"], answer: 1, why: "YouTube promotes content that extends the whole viewing session — end screens, series, and binge structures feed it.", skill: "analytics" },
    { q: "The retention graph shows a cliff in the first 3 seconds. The first fix to test is...", options: ["A new outro", "Better hashtags", "A stronger cold open — motion, stakes, or curiosity in frame one", "Posting at a different hour"], answer: 2, why: "An early cliff is a hook problem by definition; nothing downstream matters until the open holds.", skill: "analytics" }
  ]
};

